mapper.select:
SELECT last_read_message_id
FROM room_members
WHERE room_id = #{roomId}
  AND user_id = #{userId}
  AND member_status = 'ACTIVE'

mapper.update:
UPDATE room_members
SET last_read_message_id = GREATEST(COALESCE(last_read_message_id, 0), #{lastReadMessageId})
WHERE room_id = #{roomId}
  AND user_id = #{userId}
  AND member_status = 'ACTIVE'

