mapper.select:
SELECT rm.user_id
FROM room_members rm
WHERE rm.room_id = #{roomId}
  AND rm.user_id != #{senderUserId}
  AND rm.member_status = 'ACTIVE'
  AND rm.message_notification_enabled = TRUE
